import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';

const CommentForm = ({ onSubmit, isSubmitting }) => {
  const { user } = useContext(AuthContext);
  const [text, setText] = useState('');
  const [error, setError] = useState('');

  const handleChange = (e) => {
    setText(e.target.value);
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!text.trim()) {
      setError('Comment cannot be empty');
      return;
    }
    
    const success = await onSubmit(text);
    if (success) {
      setText('');
    }
  };

  if (!user) {
    return (
      <div className="bg-gray-50 dark:bg-gray-700 rounded-lg p-4 mb-4">
        <p className="text-gray-700 dark:text-gray-300 text-center">
          Please <Link to="/login" className="text-green-600 hover:text-green-800 dark:text-green-400 dark:hover:text-green-300 font-medium">log in</Link> to add a comment.
        </p>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="bg-gray-50 dark:bg-gray-700 rounded-lg p-4">
      <div className="flex items-start space-x-3">
        <div className="h-10 w-10 rounded-full bg-green-500 flex items-center justify-center text-white font-semibold">
          {user.name.charAt(0).toUpperCase()}
        </div>
        
        <div className="flex-grow">
          <textarea
            value={text}
            onChange={handleChange}
            placeholder="Add a comment..."
            className="w-full p-3 border rounded-lg resize-none min-h-[100px] bg-white dark:bg-gray-800 text-gray-900 dark:text-white border-gray-300 dark:border-gray-600 focus:border-green-500 dark:focus:border-green-400 focus:ring-2 focus:ring-green-200 dark:focus:ring-green-900"
            disabled={isSubmitting}
          />
          
          {error && (
            <p className="mt-1 text-red-500 text-sm">{error}</p>
          )}
          
          <div className="flex justify-end mt-2">
            <button
              type="submit"
              disabled={isSubmitting}
              className={`px-4 py-2 rounded-md text-white font-medium ${
                isSubmitting 
                  ? 'bg-gray-400 cursor-not-allowed' 
                  : 'bg-green-600 hover:bg-green-700 dark:bg-green-500 dark:hover:bg-green-600'
              }`}
            >
              {isSubmitting ? 'Posting...' : 'Post Comment'}
            </button>
          </div>
        </div>
      </div>
    </form>
  );
};

export default CommentForm;
